import outlines.prompts as p
p.register_filter('shout', str.upper)

@p.prompt
def greet(name):
    '{{ name | shout }}'

print(greet('world'))

@p.prompt(filters={'rev': lambda s: s[::-1]})
def greet2(name):
    '{{ name | rev }}'

print(greet2('world'))

p.unregister_filter('shout')
try:
    greet3 = p.Prompt.from_str('{{ x | shout }}')
    print(greet3(x='a'))
except Exception as e:
    print('expected error:', type(e).__name__)
